package notifier

import (
	"context"
	"fmt"
	"sync"

	"github.com/grafana/grafana-app-sdk/resource"
	promModel "github.com/prometheus/common/model"
	k8serrors "k8s.io/apimachinery/pkg/api/errors"

	alertingnotifv0alpha1 "github.com/grafana/grafana/apps/alerting/notifications/pkg/apis/alertingnotifications/v0alpha1"
	"github.com/grafana/grafana/pkg/apimachinery/identity"
	"github.com/grafana/grafana/pkg/infra/log"
	"github.com/grafana/grafana/pkg/services/apiserver/endpoints/request"
)

// autogenRouteTimings holds the timings applied to the root of the autogenerated
// policy, read from the org's Config resource. A nil field means "not set" and
// falls back to the Alertmanager route defaults when the autogen root is built.
type autogenRouteTimings struct {
	GroupWait      *promModel.Duration
	GroupInterval  *promModel.Duration
	RepeatInterval *promModel.Duration
}

// ConfigAutogenReader reads the per-org autogen route timings from the Config
// k8s resource (spec.autogenRouteTimings).
//
// The Config client is built lazily (not in the constructor) because the
// ClientGenerator blocks until the apiserver is ready, which would deadlock
// during DI. Construction failures are not cached, so a transient
// apiserver-not-ready at the first tick doesn't permanently disable reads.
type ConfigAutogenReader struct {
	logger          log.Logger
	clientGenerator resource.ClientGenerator
	namespaceMapper request.NamespaceMapper

	cfgClientMu sync.Mutex
	cfgClient   *alertingnotifv0alpha1.ConfigClient
}

// NewConfigAutogenReader constructs a ConfigAutogenReader. A nil clientGenerator
// or namespaceMapper (test paths) causes ReadAutogenRouteTimings to return
// (nil, error); MultiOrgAlertmanager treats that as "use Alertmanager defaults".
func NewConfigAutogenReader(logger log.Logger, clientGenerator resource.ClientGenerator, namespaceMapper request.NamespaceMapper) *ConfigAutogenReader {
	return &ConfigAutogenReader{
		logger:          logger,
		clientGenerator: clientGenerator,
		namespaceMapper: namespaceMapper,
	}
}

// resolveCfgClient lazily builds and caches the Config client. Successful clients
// are cached; construction failures are not, so the next call retries.
func (r *ConfigAutogenReader) resolveCfgClient() (*alertingnotifv0alpha1.ConfigClient, error) {
	r.cfgClientMu.Lock()
	defer r.cfgClientMu.Unlock()
	if r.cfgClient != nil {
		return r.cfgClient, nil
	}
	if r.clientGenerator == nil {
		return nil, fmt.Errorf("no client generator configured")
	}
	c, err := alertingnotifv0alpha1.NewConfigClientFromGenerator(r.clientGenerator)
	if err != nil {
		return nil, fmt.Errorf("construct Config client: %w", err)
	}
	r.cfgClient = c
	return r.cfgClient, nil
}

// orgServiceContext wraps ctx with a service identity scoped to the org's
// namespace for in-process k8s calls.
func (r *ConfigAutogenReader) orgServiceContext(ctx context.Context, orgID int64) (context.Context, string, error) {
	if r.namespaceMapper == nil {
		return ctx, "", fmt.Errorf("no namespace mapper configured")
	}
	ns := r.namespaceMapper(orgID)
	return identity.WithServiceIdentityForSingleNamespaceContext(ctx, ns), ns, nil
}

// ReadAutogenRouteTimings returns the org's autogen route timing overrides from
// the Config resource, or nil when none are configured (no Config resource, no
// autogenRouteTimings block, or every field unset). A nil result means the
// autogen root falls back to the Alertmanager route defaults.
func (r *ConfigAutogenReader) ReadAutogenRouteTimings(ctx context.Context, orgID int64) (*autogenRouteTimings, error) {
	c, err := r.resolveCfgClient()
	if err != nil {
		return nil, err
	}
	nsCtx, ns, err := r.orgServiceContext(ctx, orgID)
	if err != nil {
		return nil, err
	}

	cfg, err := c.Get(nsCtx, resource.Identifier{Namespace: ns, Name: alertingnotifv0alpha1.ConfigSingletonName})
	if err != nil {
		if k8serrors.IsNotFound(err) {
			return nil, nil
		}
		return nil, err
	}

	return r.parseTimings(orgID, cfg.Spec.AutogenRouteTimings), nil
}

// parseTimings converts the string durations on the Config spec into
// *model.Duration. Each field is parsed independently: a value that fails to
// parse (unexpected, since admission validates parseability) is logged and left
// unset so it falls back to the Alertmanager default instead of dropping the
// other, valid, fields. Returns nil when nothing usable is configured.
func (r *ConfigAutogenReader) parseTimings(orgID int64, spec *alertingnotifv0alpha1.ConfigV0alpha1SpecAutogenRouteTimings) *autogenRouteTimings {
	if spec == nil {
		return nil
	}
	out := &autogenRouteTimings{
		GroupWait:      r.parseDuration(orgID, "group_wait", spec.GroupWait),
		GroupInterval:  r.parseDuration(orgID, "group_interval", spec.GroupInterval),
		RepeatInterval: r.parseDuration(orgID, "repeat_interval", spec.RepeatInterval),
	}
	if out.GroupWait == nil && out.GroupInterval == nil && out.RepeatInterval == nil {
		return nil
	}
	return out
}

func (r *ConfigAutogenReader) parseDuration(orgID int64, field string, s *string) *promModel.Duration {
	if s == nil || *s == "" {
		return nil
	}
	d, err := promModel.ParseDuration(*s)
	if err != nil {
		r.logger.Warn("Ignoring unparseable autogen route timing", "org", orgID, "field", field, "value", *s, "error", err)
		return nil
	}
	return &d
}
